variablesSchema:
[
  {
    "name": "targetDir",
    "label": "部署目录",
    "placeholder": "/opt/apps/your-app",
    "required": true,
    "phase": "deploy"
  },
  {
    "name": "buildCommand",
    "label": "构建命令",
    "placeholder": "mvn -U clean package -DskipTests",
    "required": true,
    "phase": "build"
  },
  {
    "name": "jarPath",
    "label": "Jar 路径",
    "placeholder": "target/your-app.jar",
    "required": true,
    "phase": "build"
  },
  {
    "name": "startCommand",
    "label": "启动命令",
    "required": true,
    "placeholder": "nohup java -jar {{applicationName}}.jar > {{applicationName}}.log 2>&1 &",
    "phase": "deploy"
  }
]
